DROP TABLE admin_action_logs;
CREATE TABLE admin_action_logs (id bigint NOT NULL AUTO_INCREMENT, user_id int, username varchar(255), method varchar(10) NOT NULL, route varchar(255), path varchar(500) NOT NULL, action_label varchar(255), category varchar(64), target_type varchar(64), target_id varchar(64), status_code int, success tinyint(1) DEFAULT 1 NOT NULL, ip varchar(45), user_agent varchar(500), body longtext COLLATE utf8mb4_bin, before_data longtext COLLATE utf8mb4_bin, after_data longtext COLLATE utf8mb4_bin, changes longtext COLLATE utf8mb4_bin, created_at timestamp DEFAULT current_timestamp() NULL, PRIMARY KEY (id), CONSTRAINT body CHECK (json_valid(`body`)), CONSTRAINT before_data CHECK (json_valid(`before_data`)), CONSTRAINT after_data CHECK (json_valid(`after_data`)), CONSTRAINT changes CHECK (json_valid(`changes`)), INDEX idx_user (user_id), INDEX idx_category (category), INDEX idx_route (route), INDEX idx_success (success), INDEX idx_created_at (created_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE attendance_reward_applications;
CREATE TABLE attendance_reward_applications (id int NOT NULL AUTO_INCREMENT, rule_id int NOT NULL, user_id int NOT NULL, applied_at timestamp DEFAULT current_timestamp() NULL, PRIMARY KEY (id), CONSTRAINT uniq_rule_user UNIQUE (rule_id, user_id), INDEX idx_rule (rule_id), INDEX idx_user (user_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE attendance_reward_rules;
CREATE TABLE attendance_reward_rules (id int NOT NULL AUTO_INCREMENT, name varchar(150) NOT NULL, threshold int NOT NULL, add_role_ids longtext COLLATE utf8mb4_bin, remove_role_ids longtext COLLATE utf8mb4_bin, is_active tinyint(1) DEFAULT 1 NOT NULL, created_by int, created_at timestamp DEFAULT current_timestamp() NULL, PRIMARY KEY (id), CONSTRAINT add_role_ids CHECK (json_valid(`add_role_ids`)), CONSTRAINT remove_role_ids CHECK (json_valid(`remove_role_ids`)), INDEX idx_active_threshold (is_active, threshold), INDEX created_by (created_by)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE events;
CREATE TABLE events (id int NOT NULL AUTO_INCREMENT, event_type varchar(100) NOT NULL, entity_id int, user_id int, ip varchar(45), session_id varchar(64), metadata longtext COLLATE utf8mb4_bin, created_at timestamp DEFAULT current_timestamp() NULL, PRIMARY KEY (id), CONSTRAINT metadata CHECK (json_valid(`metadata`)), INDEX idx_event_type (event_type), INDEX idx_entity (entity_id), INDEX idx_user (user_id), INDEX idx_session (session_id), INDEX idx_created_at (created_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE feedback_answers;
CREATE TABLE feedback_answers (id int NOT NULL AUTO_INCREMENT, pair_id int NOT NULL, question_id int, question_prompt varchar(500) NOT NULL, rating tinyint, answer_text text, PRIMARY KEY (id), INDEX idx_pair (pair_id), INDEX idx_question (question_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE feedback_cycle_questions;
CREATE TABLE feedback_cycle_questions (id int NOT NULL AUTO_INCREMENT, cycle_id int NOT NULL, prompt varchar(500) NOT NULL, type enum('rating','text') DEFAULT 'rating' NOT NULL, direction enum('superior','peer','subordinate') NOT NULL, display_order int DEFAULT 0, is_required tinyint(1) DEFAULT 1 NOT NULL, PRIMARY KEY (id), INDEX idx_cycle_dir (cycle_id, direction, display_order)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE feedback_cycles;
CREATE TABLE feedback_cycles (id int NOT NULL AUTO_INCREMENT, title varchar(150) NOT NULL, orbat_template_id int, status enum('open','closed') DEFAULT 'open' NOT NULL, opened_at timestamp DEFAULT current_timestamp() NULL, deadline int, closed_at timestamp NULL, created_by int, PRIMARY KEY (id), INDEX idx_status (status), INDEX orbat_template_id (orbat_template_id), INDEX created_by (created_by)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE feedback_pairs;
CREATE TABLE feedback_pairs (id int NOT NULL AUTO_INCREMENT, cycle_id int NOT NULL, reviewer_user_id int NOT NULL, subject_user_id int NOT NULL, direction enum('superior','peer','subordinate') NOT NULL, is_indirect tinyint(1) DEFAULT 0 NOT NULL, status enum('pending','submitted') DEFAULT 'pending' NOT NULL, submitted_at timestamp NULL, is_adhoc tinyint(1) DEFAULT 0 NOT NULL, dedup_key tinyint DEFAULT 0, PRIMARY KEY (id), CONSTRAINT uniq_pair UNIQUE (cycle_id, reviewer_user_id, subject_user_id, dedup_key), INDEX idx_reviewer (cycle_id, reviewer_user_id), INDEX idx_subject (cycle_id, subject_user_id), INDEX reviewer_user_id (reviewer_user_id), INDEX subject_user_id (subject_user_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE feedback_questions;
CREATE TABLE feedback_questions (id int NOT NULL AUTO_INCREMENT, prompt varchar(500) NOT NULL, type enum('rating','text') DEFAULT 'rating' NOT NULL, direction enum('superior','peer','subordinate') NOT NULL, scopes set('superior','peer','subordinate'), display_order int DEFAULT 0, is_required tinyint(1) DEFAULT 1 NOT NULL, is_active tinyint(1) DEFAULT 1 NOT NULL, created_at timestamp DEFAULT current_timestamp() NULL, created_by int, PRIMARY KEY (id), INDEX idx_direction (direction, is_active, display_order), INDEX created_by (created_by)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE gallery_folders;
CREATE TABLE gallery_folders (id int NOT NULL AUTO_INCREMENT, name varchar(100) NOT NULL, parent_id int, path varchar(500) NOT NULL, created_at timestamp DEFAULT current_timestamp() NULL, PRIMARY KEY (id), INDEX idx_parent (parent_id), INDEX idx_path (path)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE gallery_images;
CREATE TABLE gallery_images (id int NOT NULL AUTO_INCREMENT, folder_id int NOT NULL, filename varchar(255) NOT NULL, original_name varchar(255) NOT NULL, caption text, uploaded_at timestamp DEFAULT current_timestamp() NULL, uploaded_by int, PRIMARY KEY (id), INDEX idx_folder (folder_id), INDEX idx_uploaded_at (uploaded_at), INDEX fk_gallery_images_uploaded_by (uploaded_by)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE info_servers;
CREATE TABLE info_servers (id int NOT NULL AUTO_INCREMENT, name varchar(100) NOT NULL, host varchar(255) NOT NULL, port int DEFAULT 2302 NOT NULL, game_type varchar(50) DEFAULT 'arma3' NOT NULL, display_order int DEFAULT 0, created_at timestamp DEFAULT current_timestamp() NULL, PRIMARY KEY (id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE kit_roles;
CREATE TABLE kit_roles (id int NOT NULL AUTO_INCREMENT, name varchar(100) NOT NULL, display_order int DEFAULT 0, PRIMARY KEY (id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE kit_slots;
CREATE TABLE kit_slots (id int NOT NULL AUTO_INCREMENT, role_id int NOT NULL, slot_name varchar(100) NOT NULL, slot_value text, display_order int DEFAULT 0, PRIMARY KEY (id), INDEX role_id (role_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE leave_of_absence;
CREATE TABLE leave_of_absence (id int NOT NULL AUTO_INCREMENT, user_id int NOT NULL, type enum('player','staff') DEFAULT 'player' NOT NULL, start_date bigint NOT NULL, end_date bigint NOT NULL, reason text NOT NULL, superior_id int, status enum('pending','approved','denied') DEFAULT 'pending', submitted_at bigint DEFAULT unix_timestamp() NOT NULL, reviewed_by int, reviewed_at bigint, review_notes text, staff_role_applied tinyint(1) DEFAULT 0 NOT NULL, PRIMARY KEY (id), INDEX superior_id (superior_id), INDEX reviewed_by (reviewed_by), INDEX idx_status (status), INDEX idx_user_dates (user_id, start_date, end_date), INDEX idx_dates (start_date, end_date)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=utf8mb4_unicode_ci;
DROP TABLE locked_periods;
CREATE TABLE locked_periods (id int NOT NULL AUTO_INCREMENT, start_date date NOT NULL, end_date date NOT NULL, label varchar(200) NOT NULL, created_by int, created_at timestamp DEFAULT current_timestamp() NULL, PRIMARY KEY (id), CONSTRAINT chk_locked_period_range CHECK (`end_date` >= `start_date`), INDEX idx_dates (start_date, end_date), INDEX fk_locked_periods_created_by (created_by)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE lore_files;
CREATE TABLE lore_files (id int NOT NULL AUTO_INCREMENT, node_id int NOT NULL, stored_name varchar(255) NOT NULL, original_name varchar(255) NOT NULL, mimetype varchar(100) NOT NULL, size int DEFAULT 0 NOT NULL, uploaded_by int, uploaded_at timestamp DEFAULT current_timestamp() NULL, PRIMARY KEY (id), INDEX fk_lore_file_node (node_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE lore_nodes;
CREATE TABLE lore_nodes (id int NOT NULL AUTO_INCREMENT, parent_id int, type enum('dir','page') DEFAULT 'page' NOT NULL, slug varchar(100) NOT NULL, title varchar(255) NOT NULL, hint varchar(500), content longtext, display_order int DEFAULT 0 NOT NULL, created_by int, created_at timestamp DEFAULT current_timestamp() NULL, updated_at timestamp DEFAULT current_timestamp() ON UPDATE current_timestamp() NULL, visibility enum('visible','hidden','draft') DEFAULT 'visible' NOT NULL, PRIMARY KEY (id), CONSTRAINT uq_lore_slug_parent UNIQUE (parent_id, slug)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE map_plan_acl;
CREATE TABLE map_plan_acl (id int NOT NULL AUTO_INCREMENT, plan_id int NOT NULL, user_id int NOT NULL, role enum('viewer','editor','admin') DEFAULT 'viewer' NOT NULL, added_at timestamp DEFAULT current_timestamp(), PRIMARY KEY (id), CONSTRAINT uniq_mpa UNIQUE (plan_id, user_id), INDEX idx_mpa_user (user_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE map_plan_annotations;
CREATE TABLE map_plan_annotations (id int NOT NULL AUTO_INCREMENT, layer_id int NOT NULL, plan_id int NOT NULL, type varchar(20) NOT NULL, geometry longtext COLLATE utf8mb4_bin NOT NULL, properties longtext COLLATE utf8mb4_bin, created_by int, created_at timestamp DEFAULT current_timestamp(), updated_at timestamp DEFAULT current_timestamp() ON UPDATE current_timestamp(), PRIMARY KEY (id), CONSTRAINT geometry CHECK (json_valid(`geometry`)), CONSTRAINT properties CHECK (json_valid(`properties`)), INDEX idx_mpa_plan (plan_id), INDEX idx_mpa_layer (layer_id), INDEX fk_mpan_creator (created_by)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE map_plan_layers;
CREATE TABLE map_plan_layers (id int NOT NULL AUTO_INCREMENT, plan_id int NOT NULL, name varchar(100) NOT NULL, color varchar(7) DEFAULT '#3498DB' NOT NULL, is_visible tinyint(1) DEFAULT 1 NOT NULL, is_public tinyint(1) DEFAULT 1 NOT NULL, display_order int DEFAULT 0 NOT NULL, created_by int, created_at timestamp DEFAULT current_timestamp(), PRIMARY KEY (id), INDEX idx_mpl_plan (plan_id), INDEX fk_mpl_creator (created_by)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE map_plans;
CREATE TABLE map_plans (id int NOT NULL AUTO_INCREMENT, owner_id int NOT NULL, name varchar(150) NOT NULL, description text, map_world varchar(80), orbat_template_id int, share_token char(32) NOT NULL, link_access enum('none','view') DEFAULT 'none' NOT NULL, created_at timestamp DEFAULT current_timestamp(), updated_at timestamp DEFAULT current_timestamp() ON UPDATE current_timestamp(), PRIMARY KEY (id), CONSTRAINT uniq_mp_share UNIQUE (share_token), INDEX idx_mp_owner (owner_id), INDEX idx_mp_orbat (orbat_template_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE medals;
CREATE TABLE medals (id int NOT NULL AUTO_INCREMENT, name varchar(100) NOT NULL, description text NOT NULL, color varchar(7) DEFAULT '#FFD700', icon varchar(50) DEFAULT 'đź?…', created_at timestamp DEFAULT current_timestamp() NULL, created_by int, PRIMARY KEY (id), INDEX created_by (created_by), INDEX idx_name (name)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE member_join_leave;
CREATE TABLE member_join_leave (id int NOT NULL AUTO_INCREMENT, discord_id varchar(20) NOT NULL, discord_name varchar(100) NOT NULL, event_type enum('join','leave') NOT NULL, account_age_days int COMMENT 'Age of Discord account in days at time of event', occurred_at datetime DEFAULT current_timestamp() NOT NULL, PRIMARY KEY (id), INDEX idx_discord_id (discord_id), INDEX idx_event_type (event_type), INDEX idx_occurred_at (occurred_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE message_activity;
CREATE TABLE message_activity (id int NOT NULL AUTO_INCREMENT, discord_id varchar(20) NOT NULL, discord_name varchar(100) NOT NULL, channel_id varchar(20) NOT NULL, channel_name varchar(100) NOT NULL, sent_at datetime DEFAULT current_timestamp() NOT NULL, PRIMARY KEY (id), INDEX idx_discord_id (discord_id), INDEX idx_channel_id (channel_id), INDEX idx_sent_at (sent_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE mission_campaigns;
CREATE TABLE mission_campaigns (id int NOT NULL AUTO_INCREMENT, name varchar(120) NOT NULL, description text, color varchar(7) DEFAULT '#fcb00d', display_order int DEFAULT 0, created_by int, created_at timestamp DEFAULT current_timestamp() NULL, PRIMARY KEY (id), INDEX idx_order (display_order), INDEX fk_mission_campaign_creator (created_by)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE mission_files;
CREATE TABLE mission_files (id int NOT NULL AUTO_INCREMENT, project_id int NOT NULL, version_number int NOT NULL, version_label varchar(100), changelog text, raw_stored_name varchar(255), raw_original_name varchar(255), raw_size bigint, pbo_stored_name varchar(255), pbo_original_name varchar(255), pbo_size bigint, uploaded_by int, uploaded_at timestamp DEFAULT current_timestamp() NULL, PRIMARY KEY (id), CONSTRAINT uniq_mission_version UNIQUE (project_id, version_number), INDEX idx_project (project_id), INDEX uploaded_by (uploaded_by)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE mission_project_assignees;
CREATE TABLE mission_project_assignees (id int NOT NULL AUTO_INCREMENT, project_id int NOT NULL, user_id int NOT NULL, role varchar(60), PRIMARY KEY (id), CONSTRAINT uniq_mission_assignee UNIQUE (project_id, user_id), INDEX idx_project (project_id), INDEX idx_user (user_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE mission_project_attachments;
CREATE TABLE mission_project_attachments (id int NOT NULL AUTO_INCREMENT, project_id int NOT NULL, stored_name varchar(255) NOT NULL, original_name varchar(255) NOT NULL, size bigint, mime varchar(120), uploaded_by int, uploaded_at timestamp DEFAULT current_timestamp() NULL, PRIMARY KEY (id), INDEX idx_project (project_id), INDEX uploaded_by (uploaded_by)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE mission_projects;
CREATE TABLE mission_projects (id int NOT NULL AUTO_INCREMENT, title varchar(200) NOT NULL, description mediumtext, status enum('planning','in_progress','blocked','review','completed','cancelled') DEFAULT 'planning' NOT NULL, priority enum('low','normal','high','urgent') DEFAULT 'normal' NOT NULL, progress tinyint DEFAULT 0 NOT NULL, start_date date, due_date date, lead_user_id int, operation_id int, campaign_id int, modpack_id int, map_world varchar(100), color varchar(7) DEFAULT '#6b8e23', created_by int, created_at timestamp DEFAULT current_timestamp() NULL, updated_at timestamp DEFAULT current_timestamp() ON UPDATE current_timestamp() NULL, PRIMARY KEY (id), INDEX idx_status (status), INDEX idx_dates (start_date, due_date), INDEX idx_lead (lead_user_id), INDEX idx_operation (operation_id), INDEX idx_modpack (modpack_id), INDEX created_by (created_by), INDEX idx_campaign (campaign_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE modpack_mods;
CREATE TABLE modpack_mods (id int NOT NULL AUTO_INCREMENT, modpack_id int NOT NULL, workshop_id bigint NOT NULL COMMENT 'Steam Workshop file ID', display_name varchar(300) NOT NULL COMMENT 'Name from the HTML file initially, updated from Steam', steam_name varchar(300) COMMENT 'Official name from Steam API', file_size bigint DEFAULT 0 COMMENT 'Size in bytes from Steam API', icon_url varchar(500) COMMENT 'Preview image URL from Steam API', steam_url varchar(500) NOT NULL COMMENT 'Full Steam Workshop URL', is_indexed tinyint(1) DEFAULT 0, indexed_at timestamp NULL, PRIMARY KEY (id), INDEX idx_modpack (modpack_id), INDEX idx_workshop (workshop_id), INDEX idx_indexed (is_indexed)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE modpacks;
CREATE TABLE modpacks (id int NOT NULL AUTO_INCREMENT, name varchar(200) NOT NULL, description text, is_pinned tinyint(1) DEFAULT 0 NOT NULL, file_path varchar(500) NOT NULL COMMENT 'Path to the original uploaded .html file', created_by int, created_at timestamp DEFAULT current_timestamp() NULL, updated_at timestamp DEFAULT current_timestamp() ON UPDATE current_timestamp() NULL, mod_count int DEFAULT 0, total_size bigint DEFAULT 0 COMMENT 'Total size in bytes', index_status enum('pending','indexing','completed','failed') DEFAULT 'pending', index_progress int DEFAULT 0 COMMENT 'Number of mods indexed so far', index_error text COMMENT 'Error message if indexing failed', PRIMARY KEY (id), INDEX idx_name (name), INDEX idx_created_by (created_by), INDEX idx_status (index_status), INDEX idx_pinned (is_pinned)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
