CREATE TABLE operation_attendance (id int NOT NULL AUTO_INCREMENT, operation_id int NOT NULL, user_id int NOT NULL, status enum('present','tentative','absent') DEFAULT 'tentative' NOT NULL, updated_at timestamp DEFAULT current_timestamp() ON UPDATE current_timestamp() NULL, PRIMARY KEY (id), CONSTRAINT unique_attendance UNIQUE (operation_id, user_id), INDEX idx_operation (operation_id), INDEX idx_user (user_id), INDEX idx_status (status)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE operation_map_annotations;
CREATE TABLE operation_map_annotations (id int NOT NULL AUTO_INCREMENT, layer_id int NOT NULL, operation_id int NOT NULL, type varchar(20) NOT NULL COMMENT 'nato_marker | polyline | polygon | rectangle | circle | text', geometry longtext COLLATE utf8mb4_bin NOT NULL, properties longtext COLLATE utf8mb4_bin, created_by int, created_at timestamp DEFAULT current_timestamp(), updated_at timestamp DEFAULT current_timestamp() ON UPDATE current_timestamp(), PRIMARY KEY (id), CONSTRAINT geometry CHECK (json_valid(`geometry`)), CONSTRAINT properties CHECK (json_valid(`properties`)), INDEX idx_oma_op (operation_id), INDEX idx_oma_layer (layer_id), INDEX fk_oma_creator (created_by)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE operation_map_layers;
CREATE TABLE operation_map_layers (id int NOT NULL AUTO_INCREMENT, operation_id int NOT NULL, name varchar(100) NOT NULL, color varchar(7) DEFAULT '#3498DB' NOT NULL, is_visible tinyint(1) DEFAULT 1 NOT NULL, is_public tinyint(1) DEFAULT 1 NOT NULL, display_order int DEFAULT 0 NOT NULL, created_by int, created_at timestamp DEFAULT current_timestamp(), PRIMARY KEY (id), INDEX idx_oml_op (operation_id), INDEX fk_oml_creator (created_by)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE operation_news;
CREATE TABLE operation_news (id int NOT NULL AUTO_INCREMENT, operation_id int NOT NULL, content text NOT NULL, posted_by int, posted_at timestamp DEFAULT current_timestamp() NULL, updated_at timestamp DEFAULT current_timestamp() ON UPDATE current_timestamp() NULL, PRIMARY KEY (id), INDEX idx_operation (operation_id), INDEX idx_posted_at (posted_at), INDEX fk_operation_news_posted_by (posted_by)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE operations;
CREATE TABLE operations (id int NOT NULL AUTO_INCREMENT, title varchar(200) NOT NULL, description text, banner_url varchar(500) DEFAULT '/images/operations/default-banner.jpg', created_by int, host_id int, discord_forum_post_id varchar(255), discord_thread_id varchar(255), created_at timestamp DEFAULT current_timestamp() NULL, updated_at timestamp DEFAULT current_timestamp() ON UPDATE current_timestamp() NULL, is_published tinyint(1) DEFAULT 1, orbat_template_id int, modpack_id int, orbat_type enum('none','fixed','dynamic') DEFAULT 'none', operation_type enum('main','side') DEFAULT 'main' NOT NULL, discord_message_id varchar(255), start_time int(10), end_time int(10), orbat_published tinyint(1) DEFAULT 1 NOT NULL, map_world varchar(64), PRIMARY KEY (id), INDEX idx_created_by (created_by), INDEX fk_operation_orbat_template (orbat_template_id), INDEX idx_operation_host (host_id), INDEX idx_discord_thread (discord_thread_id), INDEX idx_operation_type (operation_type), INDEX fk_operation_modpack (modpack_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE orbat_assignments;
CREATE TABLE orbat_assignments (id int NOT NULL AUTO_INCREMENT, role_id int NOT NULL, user_id int NOT NULL, assigned_by int, assigned_at timestamp DEFAULT current_timestamp() NULL, PRIMARY KEY (id), CONSTRAINT unique_role_assignment UNIQUE (role_id), INDEX idx_role (role_id), INDEX idx_user (user_id), INDEX assigned_by (assigned_by)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE orbat_attendance;
