CREATE TABLE orbat_roles (id int NOT NULL AUTO_INCREMENT, squad_id int NOT NULL, role_name varchar(100) NOT NULL, slot_type_id int, display_order int DEFAULT 0, created_at timestamp DEFAULT current_timestamp() NULL, is_editor tinyint(1) DEFAULT 0 NOT NULL COMMENT 'If TRUE, the user assigned to this role can manage assignments within this squad', team_id int, PRIMARY KEY (id), INDEX idx_squad (squad_id), INDEX idx_order (display_order), INDEX fk_orbat_roles_team (team_id), INDEX idx_slot_type (slot_type_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
