DROP TABLE role_permissions;
CREATE TABLE role_permissions (role_id int NOT NULL, permission_id int NOT NULL, PRIMARY KEY (role_id, permission_id), INDEX fk_rp_permission (permission_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE roles;
CREATE TABLE roles (id int NOT NULL AUTO_INCREMENT, name varchar(100) NOT NULL, description varchar(255), is_system tinyint(1) DEFAULT 0 COMMENT 'System roles cannot be deleted', created_at timestamp DEFAULT current_timestamp() NULL, PRIMARY KEY (id), CONSTRAINT role_name UNIQUE (name)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE roster_members;
CREATE TABLE roster_members (id int NOT NULL AUTO_INCREMENT, discord_id varchar(50) NOT NULL, discord_username varchar(100) NOT NULL, discord_global_name varchar(100), discord_avatar varchar(255), nickname varchar(100), highest_role_id int, joined_at timestamp NULL, last_synced timestamp DEFAULT current_timestamp() ON UPDATE current_timestamp() NULL, is_visible tinyint(1) DEFAULT 1, departments longtext COLLATE utf8mb4_bin, PRIMARY KEY (id), CONSTRAINT discord_id UNIQUE (discord_id), CONSTRAINT departments CHECK (json_valid(`departments`)), INDEX idx_discord_id (discord_id), INDEX idx_highest_role (highest_role_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE roster_roles;
CREATE TABLE roster_roles (id int NOT NULL AUTO_INCREMENT, name varchar(100) NOT NULL, discord_role_id varchar(50) NOT NULL, hierarchy_level int NOT NULL, color varchar(7) DEFAULT '#3498DB', description text, display_on_roster tinyint(1) DEFAULT 1, created_at timestamp DEFAULT current_timestamp() NULL, PRIMARY KEY (id), CONSTRAINT discord_role_id UNIQUE (discord_role_id), INDEX idx_hierarchy (hierarchy_level), INDEX idx_discord_role (discord_role_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE sessions;
CREATE TABLE sessions (session_id varchar(128) COLLATE utf8mb4_bin NOT NULL, expires int unsigned NOT NULL, data mediumtext COLLATE utf8mb4_bin, PRIMARY KEY (session_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE slot_type_superiors;
CREATE TABLE slot_type_superiors (slot_type_id int NOT NULL, superior_type_id int NOT NULL, PRIMARY KEY (slot_type_id, superior_type_id), INDEX superior_type_id (superior_type_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE slot_types;
CREATE TABLE slot_types (id int NOT NULL AUTO_INCREMENT, name varchar(100) NOT NULL, abbreviation varchar(20), display_order int DEFAULT 0, created_by int, created_at timestamp DEFAULT current_timestamp() NULL, is_leader tinyint(1) DEFAULT 0 NOT NULL, PRIMARY KEY (id), INDEX idx_display_order (display_order), INDEX created_by (created_by)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE tools;
CREATE TABLE tools (id int NOT NULL AUTO_INCREMENT, title varchar(100) NOT NULL, description text, image_url varchar(255), link varchar(255) NOT NULL, is_visible tinyint(1) DEFAULT 1, order_index int DEFAULT 0, created_at timestamp DEFAULT current_timestamp() NULL, updated_at timestamp DEFAULT current_timestamp() ON UPDATE current_timestamp() NULL, PRIMARY KEY (id), INDEX idx_visible_order (is_visible, order_index)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE trainings;
CREATE TABLE trainings (id int NOT NULL AUTO_INCREMENT, name varchar(100) NOT NULL, discord_role_id varchar(50) NOT NULL, description text, color varchar(7) DEFAULT '#3498DB', image_url varchar(500) DEFAULT '/images/badges/default-training.png', icon varchar(50) DEFAULT '?', display_order int DEFAULT 0, created_at timestamp DEFAULT current_timestamp() NULL, created_by int, PRIMARY KEY (id), CONSTRAINT discord_role_id UNIQUE (discord_role_id), INDEX idx_name (name), INDEX idx_discord_role (discord_role_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE user_medals;
CREATE TABLE user_medals (id int NOT NULL AUTO_INCREMENT, user_id int NOT NULL, medal_id int NOT NULL, awarded_by int NOT NULL, awarded_at timestamp DEFAULT current_timestamp() NULL, notes text, PRIMARY KEY (id), CONSTRAINT unique_user_medal UNIQUE (user_id, medal_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE user_roles;
CREATE TABLE user_roles (user_id int NOT NULL, role_id int NOT NULL, assigned_by int, assigned_at timestamp DEFAULT current_timestamp() NULL, PRIMARY KEY (user_id, role_id), INDEX fk_ur_role (role_id), INDEX fk_ur_assigned_by (assigned_by)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE user_trainings;
CREATE TABLE user_trainings (id int NOT NULL AUTO_INCREMENT, user_id int NOT NULL, training_id int NOT NULL, synced_at timestamp DEFAULT current_timestamp() NULL, last_verified timestamp DEFAULT current_timestamp() ON UPDATE current_timestamp() NULL, PRIMARY KEY (id), CONSTRAINT unique_user_training UNIQUE (user_id, training_id), INDEX idx_user (user_id), INDEX idx_training (training_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
DROP TABLE users;
CREATE TABLE users (id int NOT NULL AUTO_INCREMENT, username varchar(50) NOT NULL, password_hash varchar(255), is_admin tinyint(1) DEFAULT 0, discord_id varchar(50), discord_username varchar(100), discord_global_name varchar(100), discord_avatar varchar(255), discord_access_token varchar(500), discord_refresh_token varchar(500), auth_type enum('local','discord') DEFAULT 'local', created_at timestamp DEFAULT current_timestamp() NULL, last_login timestamp NULL, PRIMARY KEY (id), CONSTRAINT username UNIQUE (username), CONSTRAINT discord_id UNIQUE (discord_id), INDEX idx_username (username), INDEX idx_discord_id (discord_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 DEFAULT COLLATE=uca1400_ai_ci;
